const body = $input.first().json.body;
const raw = body?.url?.trim();

if (!raw) {
  return [{
    json: {
      status: 422,
      message: "Missing 'url' field in request body."
    }
  }];
}

// Strip protocol and path to get clean domain
const domain = raw.replace(/^https?:\/\//i, "").replace(/\/.*$/, "");

// Validate domain format
const isValid = /^[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z]{2,})+$/.test(domain);

if (!isValid) {
  throw new Error(`Invalid URL: "${raw}" is not a valid domain or URL.`);
}
return [{
  json: {
    status: 200,
    domain: domain,
    url: `https://${domain}`
  }
}];

return $('Extract business signals with AI').all().map(item => ({
  json: item.json.output
}));
